            dp[t][i] = make([]int64, n)
            for j := 0; j < n; j++ {
                dp[t][i][j] = INF
            }
        }
    }

    dp[0][0][0] = 0

    for i := 0; i < m; i++ {
        for j := 0; j < n; j++ {
            if i == 0 && j == 0 {
                continue
            }
            fromTop := INF
            if i > 0 && dp[0][i-1][j] != INF {
                fromTop = dp[0][i-1][j] + grid[i][j]
            }
            fromLeft := INF
            if j > 0 && dp[0][i][j-1] != INF {
                fromLeft = dp[0][i][j-1] + grid[i][j]
            }
            if fromTop < fromLeft {
                dp[0][i][j] = fromTop
            } else {
                dp[0][i][j] = fromLeft
            }
        }
    }

