                    continue
                }
                v := int(grid[i][j])
                if dp[t][i][j] < minArr[v] {
                    minArr[v] = dp[t][i][j]
                }
            }
        }

        for val := maxValInt - 1; val >= 0; val-- {
            if minArr[val] > minArr[val+1] {
                minArr[val] = minArr[val+1]
            }
        }

        for i := 0; i < m; i++ {
            for j := 0; j < n; j++ {
                v := int(grid[i][j])
                if minArr[v] < dp[t+1][i][j] {
                    dp[t+1][i][j] = minArr[v]
                }
            }
        }

        for i := 0; i < m; i++ {
            for j := 0; j < n; j++ {
                fromTop := INF
                if i > 0 && dp[t+1][i-1][j] != INF {
                    fromTop = dp[t+1][i-1][j] + grid[i][j]
                }
                fromLeft := INF
                if j > 0 && dp[t+1][i][j-1] != INF {
                    fromLeft = dp[t+1][i][j-1] + grid[i][j]
                }
                minCost := fromTop
                if fromLeft < minCost {
                    minCost = fromLeft
                }
                if minCost != INF && minCost < dp[t+1][i][j] {
                    dp[t+1][i][j] = minCost
                }
            }
        }
    }

    ans := INF
    for t := 0; t <= kInt; t++ {
        if dp[t][m-1][n-1] < ans {
            ans = dp[t][m-1][n-1]
        }
    }
    return ans
}
