import (
	"container/heap"
	"math"
)

type State struct {
	cost int64
	i, j int
	t    int
}

type StateHeap []State

func (h StateHeap) Len() int           { return len(h) }
func (h StateHeap) Less(i, j int) bool { return h[i].cost < h[j].cost }
func (h StateHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }
func (h *StateHeap) Push(x interface{}) {
	*h = append(*h, x.(State))
}
func (h *StateHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

func solve(grid [][]int64, k int64) int64 {
	kk := int(k)
	m := len(grid)
	if m == 0 {
		return 0
	}
	n := len(grid[0])

	maxVal := 0
	for i := 0; i < m; i++ {
		for j := 0; j < n; j++ {
			val := int(grid[i][j])
			if val > maxVal {
				maxVal = val
			}
		}
	}

	leqList := make([][][2]int, maxVal+1)
	for v := 0; v <= maxVal; v++ {
		leqList[v] = make([][2]int, 0)
		for i := 0; i < m; i++ {
			for j := 0; j < n; j++ {
				if int(grid[i][j]) <= v {
					leqList[v] = append(leqList[v], [2]int{i, j})
				}
			}
		}
	}

	dist := make([][][]int64, m)
	for i := 0; i < m; i++ {
		dist[i] = make([][]int64, n)
		for j := 0; j < n; j++ {
			dist[i][j] = make([]int64, kk+1)
			for t := 0; t <= kk; t++ {
				dist[i][j][t] = math.MaxInt64
			}
		}
	}

	h := &StateHeap{}
	heap.Init(h)
	dist[0][0][kk] = 0
	heap.Push(h, State{0, 0, 0, kk})

	for h.Len() > 0 {
		st := heap.Pop(h).(State)
		i, j, t := st.i, st.j, st.t

		if i == m-1 && j == n-1 {
			return st.cost
		}

		if st.cost > dist[i][j][t] {
			continue
		}

		dirs := []struct{ dx, dy int }{{0, 1}, {1, 0}}
		for _, d := range dirs {
			ni, nj := i+d.dx, j+d.dy
			if ni < 0 || ni >= m || nj < 0 || nj >= n {
				continue
			}
			newCost := st.cost + grid[ni][nj]
			if newCost < dist[ni][nj][t] {
				dist[ni][nj][t] = newCost
				heap.Push(h, State{newCost, ni, nj, t})
			}
		}

		if t > 0 {
			v0 := int(grid[i][j])
			if v0 > maxVal {
				v0 = maxVal
			}
			for _, cell := range leqList[v0] {
				ni, nj := cell[0], cell[1]
				if st.cost < dist[ni][nj][t-1] {
					dist[ni][nj][t-1] = st.cost
					heap.Push(h, State{st.cost, ni, nj, t - 1})
				}
			}
		}
	}

	ans := int64(math.MaxInt64)
	for t := 0; t <= kk; t++ {
		if dist[m-1][n-1][t] < ans {
			ans = dist[m-1][n-1][t]
		}
	}
	return ans
}
