    dp := make([][][]int64, m)
    for i := range dp {
        dp[i] = make([][]int64, n)
        for j := range dp[i] {
            dp[i][j] = make([]int64, k+1)
            for t := int64(0); t <= k; t++ {
                dp[i][j][t] = INF
            }
        }
    }

    dp[0][0][0] = 0

    for i := 0; i < m; i++ {
        for j := 0; j < n; j++ {
            if i == 0 && j == 0 {
                continue
            }
            var candidate1, candidate2 int64 = INF, INF
            if i > 0 {
                candidate1 = dp[i-1][j][0] + grid[i][j]
            }
            if j > 0 {
                candidate2 = dp[i][j-1][0] + grid[i][j]
            }
            if candidate1 < candidate2 {
                dp[i][j][0] = candidate1
            } else {
                dp[i][j][0] = candidate2
            }
        }
    }

